svg.script:
(function(){
  const svg = document.currentScript.ownerSVGElement;
  const isStatic = svg.getAttribute('data-static') === 'true';
  const reduce = matchMedia('(prefers-reduced-motion: reduce)').matches && svg.getAttribute('data-animate') !== 'force';
  if(isStatic || reduce){ return; }

  /* ----------------------------
     Constants from original SMIL
     ---------------------------- */
  const TOTAL = 3.000;                 // seconds
  const EASE  = cubicBezier(0.25,0.10,0.25,1.00);
  const FPS   = 60;                    // change to 24/30/etc. for coarse frame stepping
  const DT    = 1 / FPS;               // frame step (sec)

  // Sweep plateaus/targets
  const C_MAX  = 200;
  const X_MAX  = 200;
  const P_MAX  = 240;
  const L_MAX  = 240;
  const U_MAX  = 240;
  const S_MAX  = 260;

  // Timings (sec) — straight from the original file
  const t = {
    // cyan grows (0.12s each, staggered)
    cGrow0: 0.00, cGrow1: 0.12,
    xGrow0: 0.12, xGrow1: 0.24,
    pGrow0: 0.24, pGrow1: 0.36,
    lGrow0: 0.36, lGrow1: 0.48,
    uGrow0: 0.48, uGrow1: 0.60,
    sGrow0: 0.60, sGrow1: 0.72,

    // sReveal.end = 0.72 -> plus begins
    plusIn0: 0.72,        // opacity 0→1 over 0.20s; scale 0→1.08 @70% then 1.08→1
    plusIn1: 0.92,
    plusOver: 0.86,       // overshoot peak (70% of 0.20s)

    // spins (each 0.45s) with 0.02s wait after popScale
    spinLR0: 0.94, spinLR1: 1.39,
    spinRL0: 1.39, spinRL1: 1.84,

    // pop-out (0.12s)
    plusOut0: 1.84, plusOut1: 1.96,

    // cyan collapses (0.03s each, staggered after plusOut)
    sCol0: 1.96, sCol1: 1.99,
    uCol0: 1.99, uCol1: 2.02,
    lCol0: 2.02, lCol1: 2.05,
    pCol0: 2.05, pCol1: 2.08,
    xCol0: 2.08, xCol1: 2.11,
    cCol0: 2.11, cCol1: 2.14,

    // x wiggle (0.60s total; two equal segments)
    xWig0: 0.18, xWigMid: 0.48, xWig1: 0.78, // 0.30s each half
    // x pop scale (0.25s; two equal segments)
    xSc0: 0.42, xScMid: 0.545, xSc1: 0.67
  };

  /* ----------------------------
     Element refs
     ---------------------------- */
  const cSweep   = svg.getElementById('cSweep');
  const xSweep   = svg.getElementById('xSweep');
  const pClip    = svg.getElementById('pClipRect');
  const lClip    = svg.getElementById('lClipRect');
  const uClip    = svg.getElementById('uClipRect');
  const sClip    = svg.getElementById('sClipRect');

  const xBaseWrap = svg.getElementById('xBaseWrap');
  const xMoveWrap = svg.getElementById('xMoveWrap');

  const plusGlyph = svg.getElementById('plusGlyph');

  /* ----------------------------
     Helpers
     ---------------------------- */
  function clamp(v, a, b){ return v < a ? a : (v > b ? b : v); }
  function lerp(a, b, p){ return a + (b - a) * p; }

  // Piecewise eased segment: returns value (or null if out of segment)
  function easedSegment(now, t0, t1, v0, v1){
    if(now <= t0) return null;
    if(now >= t1) return null;
    const p = (now - t0) / (t1 - t0);
    return lerp(v0, v1, EASE(p));
  }

  // Expand/hold/collapse utility
  function sweepWidth(now, g0, g1, plateau, c0, c1){
    // grow
    let v = easedSegment(now, g0, g1, 0, plateau);
    if(v !== null) return v;
    // hold
    if(now >= g1 && now < c0) return plateau;
    // collapse
    v = easedSegment(now, c0, c1, plateau, 0);
    if(v !== null) return v;
    // else baseline
    return (now < g0 || now >= c1) ? 0 : plateau;
  }

  // X wiggle: translateY 0 → -0.8 → 0
  function xTranslateY(now){
    const up = easedSegment(now, t.xWig0, t.xWigMid, 0, -0.8);
    if(up !== null) return up;
    const down = easedSegment(now, t.xWigMid, t.xWig1, -0.8, 0);
    if(down !== null) return down;
    return 0;
  }

  // X scale: 1 → 1.06 → 1
  function xScale(now){
    const up = easedSegment(now, t.xSc0, t.xScMid, 1, 1.06);
    if(up !== null) return up;
    const dn = easedSegment(now, t.xScMid, t.xSc1, 1.06, 1);
    if(dn !== null) return dn;
    return 1;
  }

  // Plus transform + opacity
  function plusState(now){
    // default hidden
    let scale = 0, rot = 0, op = 0;

    // pop-in opacity 0→1 (0.72–0.92)
    if(now > t.plusIn0 && now < t.plusIn1){
      op = EASE((now - t.plusIn0) / (t.plusIn1 - t.plusIn0));
    } else if(now >= t.plusIn1 && now < t.plusOut0){
      op = 1;
    } else if(now >= t.plusOut0 && now < t.plusOut1){
      op = 1 - EASE((now - t.plusOut0) / (t.plusOut1 - t.plusOut0));
    } else {
      op = 0;
    }

    // scale: 0→1.08 (to 0.86s), then 1.08→1 (to 0.92s), hold, then 1→0 on popOut
    if(now > t.plusIn0 && now < t.plusOver){
      scale = lerp(0, 1.08, EASE((now - t.plusIn0) / (t.plusOver - t.plusIn0)));
    } else if(now >= t.plusOver && now < t.plusIn1){
      scale = lerp(1.08, 1.0, EASE((now - t.plusOver) / (t.plusIn1 - t.plusOver)));
    } else if(now >= t.plusIn1 && now < t.plusOut0){
      scale = 1.0;
    } else if(now >= t.plusOut0 && now < t.plusOut1){
      scale = lerp(1.0, 0.0, EASE((now - t.plusOut0) / (t.plusOut1 - t.plusOut0)));
    } else {
      scale = 0.0;
    }

    // rotations: 0.94–1.39 => 0→360; 1.39–1.84 => 360→0
    if(now > t.spinLR0 && now < t.spinLR1){
      rot = lerp(0, 360, EASE((now - t.spinLR0) / (t.spinLR1 - t.spinLR0)));
    } else if(now >= t.spinRL0 && now < t.spinRL1){
      rot = lerp(360, 0, EASE((now - t.spinRL0) / (t.spinRL1 - t.spinRL0)));
    } else {
      rot = (now < t.spinLR0) ? 0 : 0; // rests at 0
    }
    return {scale, rot, op};
  }

  // Cubic-bezier timing (returns a function f(p) mapping [0,1]→[0,1])
  function cubicBezier(x1, y1, x2, y2){
    // Precompute coefficients
    const cx = 3 * x1, bx = 3 * (x2 - x1) - cx, ax = 1 - cx - bx;
    const cy = 3 * y1, by = 3 * (y2 - y1) - cy, ay = 1 - cy - by;

    function sampleX(t){ return ((ax * t + bx) * t + cx) * t; }
    function sampleY(t){ return ((ay * t + by) * t + cy) * t; }
    function sampleXDeriv(t){ return (3 * ax * t + 2 * bx) * t + cx; }

    // Given x in [0,1], find t in [0,1] such that sampleX(t) ≈ x
    function solveT(x){
      let t = x; // initial guess
      for(let i=0;i<6;i++){
        const xEst = sampleX(t) - x;
        const dEst = sampleXDeriv(t);
        if(Math.abs(xEst) < 1e-7) return t;
        if(Math.abs(dEst) < 1e-7) break;
        t -= xEst / dEst;
      }
      // fallback to bisection
      let t0 = 0, t1 = 1;
      t = x;
      while(t0 < t1){
        const xEst = sampleX(t);
        if(Math.abs(xEst - x) < 1e-7) return t;
        if(x > xEst) t0 = t; else t1 = t;
        t = (t0 + t1) * 0.5;
      }
      return t;
    }
    return function(p){
      if(p <= 0) return 0;
      if(p >= 1) return 1;
      return sampleY(solveT(p));
    };
  }

  /* ----------------------------
     Frame loop (quantized)
     ---------------------------- */
  const start = performance.now();
  function step(){
    const nowMs = performance.now();
    // Time in seconds within current cycle
    const elapsed = ((nowMs - start)/1000) % TOTAL;
    // Quantize to discrete frame boundary
    const frameIndex = Math.floor(elapsed / DT);
    const tFrame = frameIndex * DT;

    // Cyan widths
    const cW = sweepWidth(tFrame, t.cGrow0, t.cGrow1, C_MAX, t.cCol0, t.cCol1);
    const xW = sweepWidth(tFrame, t.xGrow0, t.xGrow1, X_MAX, t.xCol0, t.xCol1);
    const pW = sweepWidth(tFrame, t.pGrow0, t.pGrow1, P_MAX, t.pCol0, t.pCol1);
    const lW = sweepWidth(tFrame, t.lGrow0, t.lGrow1, L_MAX, t.lCol0, t.lCol1);
    const uW = sweepWidth(tFrame, t.uGrow0, t.uGrow1, U_MAX, t.uCol0, t.uCol1);
    const sW = sweepWidth(tFrame, t.sGrow0, t.sGrow1, S_MAX, t.sCol0, t.sCol1);

    // Apply widths (attributes are valid CSS/SVG presentation attrs)
    cSweep.setAttribute('width',  cW.toFixed(2));
    xSweep.setAttribute('width',  xW.toFixed(2));
    pClip.setAttribute('width',   pW.toFixed(2));
    lClip.setAttribute('width',   lW.toFixed(2));
    uClip.setAttribute('width',   uW.toFixed(2));
    sClip.setAttribute('width',   sW.toFixed(2));

    // X wiggle and pop (same on base and overlay)
    const yT = xTranslateY(tFrame);
    const sX = xScale(tFrame);
    const xTransform = `translate(0,${yT.toFixed(3)}) scale(${sX.toFixed(4)})`;
    xBaseWrap.setAttribute('transform', xTransform);
    xMoveWrap.setAttribute('transform', xTransform);

    // Plus accent
    const ps = plusState(tFrame);
    plusGlyph.setAttribute('opacity', ps.op.toFixed(3));
    // Avoid negative/NaN transforms
    const scl = clamp(ps.scale, 0, 3);
    const rot = isFinite(ps.rot) ? ps.rot : 0;
    plusGlyph.setAttribute('transform', `rotate(${rot.toFixed(3)}) scale(${scl.toFixed(4)})`);

    requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
})();
